function getNestedValue(tree: TranslationTree, key: string): string | undefined {
  return key.split(".").reduce<TranslationLeaf | TranslationTree | undefined>((acc, part) => {
    if (!acc || typeof acc === "string") return undefined;
    return acc[part];
  }, tree) as string | undefined;
}

function interpolate(template: string, vars?: Record<string, string | number>): string {
  if (!vars) return template;
  return template.replace(/\{\{(\w+)\}\}/g, (_, name: string) => String(vars[name] ?? ""));
}

export function detectLocale(input?: string | null): Locale {
  if (!input) return DEFAULT_LOCALE;
  const normalized = input.toLowerCase();
  if (normalized.startsWith("en")) return "en";
  if (normalized.startsWith("es")) return "es";
  if (normalized.startsWith("pt")) return "pt";
  return DEFAULT_LOCALE;
}

export function getTranslation(locale: Locale, key: string, vars?: Record<string, string | number>): string {
  const active = getNestedValue(translations[locale], key);
  const fallback = getNestedValue(translations[DEFAULT_LOCALE], key);
  const message = active ?? fallback ?? key;
  return interpolate(message, vars);
}












